+/// Shared node-health vocabulary for transport-backed fleet state.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+pub enum NodeHealth {
+    Healthy,
+    Degraded,
+    Unreachable,
+    Quarantined,
+}
