+impl NodeStatus {
+    pub fn new(
+        node_id: impl Into<String>,
+        last_seen: chrono::DateTime<chrono::Utc>,
+        quarantine_version: u64,
+        health: NodeHealth,
+    ) -> Result<Self, FleetTransportError> {
+        let status = Self {
+            node_id: node_id.into(),
+            last_seen,
+            quarantine_version,
+            health,
+        };
+        status.validate()?;
+        Ok(status)
+    }
