+            self.ensure_initialized()?;
+            status.validate()?;
+            let mut nodes = self
+                .nodes
+                .lock()
+                .map_err(|_| FleetTransportError::lock_contention("nodes lock poisoned"))?;
+            nodes.insert(status.node_id.clone(), status.clone());
+            Ok(status.clone())
+        }
