+        fn list_stale_nodes(
+            &self,
+            now: chrono::DateTime<chrono::Utc>,
+            staleness_threshold: Duration,
+        ) -> Result<Vec<NodeStatus>, FleetTransportError> {
+            self.ensure_initialized()?;
+            let staleness_threshold =
